1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Array<{ items: Item[] }> };
3	
4	const PROCESSING_FEE = 5;
5	const COMPONENT_BASE_PER_ITEM = 25;
6	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
7	
8	const CURSED_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
13	const LOYALTY_YEARS_THRESHOLD = 2;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	
16	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	};
22	
23	export function runScenario(input: unknown): unknown {
24	  const { customer, steps } = input as Scenario;
25	  const years = customer?.yearsWithMHPCO ?? 0;
26	  const results = steps.map((step, index) => ({
27	    premium: computePremium(step.items, years, index >= 1),
28	  }));
29	  return { results };
30	}
31	
32	function computePremium(items: Item[], years: number, isFollowUp: boolean): number {
33	  if (items.length === 0) return PROCESSING_FEE;
34	  if (items.every(isComponent)) return componentsPremium(items);
35	  return mainItemsPremium(items, years, isFollowUp);
36	}
37	
38	function mainItemsPremium(items: Item[], years: number, isFollowUp: boolean): number {
39	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
40	  const itemSubtotalSum = items.reduce((sum, item) => sum + itemSubtotal(item), 0);
41	  const policyMod = (cond: boolean, rate: number) => (cond ? policyBase * rate : 0);
42	  const loyaltyDiscount = policyMod(years >= LOYALTY_YEARS_THRESHOLD, LOYALTY_DISCOUNT_RATE);
43	  const followUpDiscount = policyMod(isFollowUp, FOLLOW_UP_DISCOUNT_RATE);
44	  return Math.ceil(itemSubtotalSum - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
45	}
46	
47	function itemSubtotal(item: Item): number {
48	  const base = BASE_PREMIUM_BY_TYPE[item.type];
49	  const surchargeIf = (cond: boolean, rate: number) => (cond ? base * rate : 0);
50	  const cursedSurcharge = surchargeIf(item.cursed === true, CURSED_SURCHARGE_RATE);
51	  const highEnchSurcharge = surchargeIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
52	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
53	  return base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup;
54	}
55	
56	function isHighlyEnchanted(item: Item): boolean {
57	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
58	}
59	
60	function componentsPremium(items: Item[]): number {
61	  const runes = items.filter((i) => i.type === "rune").length;
62	  const moonstones = items.filter((i) => i.type === "moonstone").length;
63	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
64	}
65	
66	function componentTypeBase(count: number): number {
67	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
68	}
69	
70	function isComponent(item: Item): boolean {
71	  return item.type === "rune" || item.type === "moonstone";
72	}
73	
74	function premiumFromBase(base: number): number {
75	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
76	}
